using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipFile now defaults to UTF-8 with the EFS bit set.
        // Legacy Java consumer expects Shift-JIS, so specify the encoding explicitly.
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create,
            entryNameEncoding: Encoding.GetEncoding("shift_jis"));
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: [FromKeyedServices] now strictly requires a
// keyed registration; non-keyed fallback no longer occurs.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

